from langchain_text_splitters import (
    RecursiveCharacterTextSplitter,
    Language,
)
import tiktoken

enc = tiktoken.encoding_for_model("text-embedding-3-small")
tok = lambda text: len(enc.encode(text))

# Type-specific splitters
SPLITTERS = {
    "prose": RecursiveCharacterTextSplitter(
        chunk_size=512, chunk_overlap=64, length_function=tok,
    ),
    "qa": RecursiveCharacterTextSplitter(
        chunk_size=128, chunk_overlap=16, length_function=tok,
    ),
    "code_python": RecursiveCharacterTextSplitter.from_language(
        language=Language.PYTHON,
        chunk_size=256, chunk_overlap=32,
    ),
    "code_js": RecursiveCharacterTextSplitter.from_language(
        language=Language.JS,
        chunk_size=256, chunk_overlap=32,
    ),
    "default": RecursiveCharacterTextSplitter(
        chunk_size=512, chunk_overlap=64, length_function=tok,
    ),
}

def route_splitter(doc):
    """Return the appropriate splitter for a LangChain Document."""
    doc_type = doc.metadata.get("doc_type", "")
    source   = doc.metadata.get("source", "")

    if source.endswith(".py"):
        return SPLITTERS["code_python"]
    if source.endswith((".js", ".ts")):
        return SPLITTERS["code_js"]
    if doc_type in ("faq", "qa_sheet"):
        return SPLITTERS["qa"]
    if doc_type in ("report", "article", "whitepaper"):
        return SPLITTERS["prose"]
    return SPLITTERS["default"]

def adaptive_split(docs):
    chunks = []
    for doc in docs:
        splitter = route_splitter(doc)
        chunks.extend(splitter.split_documents([doc]))
    return chunks
